  1→# Tailscale configuration
  2→{
  3→  config,
  4→  lib,
  5→  pkgs,
  6→  ...
  7→}:
  8→with lib;
  9→let
 10→  cfg = config.modules.tailscale;
 11→
 12→  # Check if user-level services should be enabled
 13→  # Only enable if serviceConfig is explicitly set (not for system-level service only)
 14→  configEnabled = cfg.serviceConfig != { } && cfg.serviceConfig != null;
 15→
 16→  # System service unit file (for non-NixOS Linux)
 17→  tailscaledServiceFile = pkgs.writeText "tailscaled.service" ''
 18→    [Unit]
 19→    Description=Tailscale node agent
 20→    Documentation=https://tailscale.com/kb/
 21→    Wants=network-pre.target
 22→    After=network-pre.target NetworkManager.service systemd-resolved.service
 23→
 24→    [Service]
 25→    ExecStartPre=${cfg.tailscaled.package}/bin/tailscaled --cleanup
 26→    ExecStart=${cfg.tailscaled.package}/bin/tailscaled --state=/var/lib/tailscale/tailscaled.state --socket=/run/tailscale/tailscaled.sock --port ${toString cfg.port}
 27→    ExecStopPost=${cfg.tailscaled.package}/bin/tailscaled --cleanup
 28→    Restart=on-failure
 29→    RuntimeDirectory=tailscale
 30→    RuntimeDirectoryMode=0755
 31→    StateDirectory=tailscale
 32→    StateDirectoryMode=0700
 33→    CacheDirectory=tailscale
 34→    CacheDirectoryMode=0750
 35→    Type=notify
 36→
 37→    [Install]
 38→    WantedBy=multi-user.target
 39→  '';
 40→in
 41→{
 42→  options.modules.tailscale = {
 43→    enable = mkEnableOption "Tailscale VPN service";
 44→
 45→    # Tailscale daemon configuration
 46→    tailscaled = {
 47→      package = mkOption {
 48→        type = types.package;
 49→        default = pkgs.tailscale;
 50→        description = "Tailscale package to use";
 51→      };
 52→
 53→      stateDir = mkOption {
 54→        type = types.str;
 55→        default = "${config.xdg.dataHome}/tailscale";
 56→        description = "Directory for Tailscale state files";
 57→      };
 58→
 59→      socketPath = mkOption {
 60→        type = types.str;
 61→        default = "${config.home.homeDirectory}/.local/run/tailscale/tailscaled.sock";
 62→        description = "Socket path for Tailscale daemon";
 63→      };
 64→    };
 65→
 66→    # Optional auth key
 67→    authKey = mkOption {
 68→      type = types.str;
 69→      default = "";
 70→      description = "Tailscale auth key (use agenix for secrets)";
 71→    };
 72→
 73→    # Optional auth key file (better for secrets)
 74→    authKeyFile = mkOption {
 75→      type = types.str;
 76→      default = "";
 77→      description = "Path to file containing Tailscale auth key (better for secrets)";
 78→    };
 79→
 80→    # Tailscale up options
 81→    acceptRoutes = mkOption {
 82→      type = types.bool;
 83→      default = false;
 84→      description = "Accept routes from other nodes";
 85→    };
 86→
 87→    advertiseExitNode = mkOption {
 88→      type = types.bool;
 89→      default = false;
 90→      description = "Advertise as exit node";
 91→    };
 92→
 93→    useExitNode = mkOption {
 94→      type = types.str;
 95→      default = "";
 96→      description = "Use specific node as exit node";
 97→    };
 98→
 99→    extraUpArgs = mkOption {
100→      type = types.listOf types.str;
101→      default = [ ];
102→      description = "Additional arguments to pass to tailscale up";
103→    };
104→
105→    port = mkOption {
106→      type = types.int;
107→      default = 41641;
108→      description = "UDP port for Tailscale traffic";
109→    };
110→
111→    installSystemService = mkOption {
112→      type = types.bool;
113→      default = true;
114→      description = "Install system-level tailscaled service (requires sudo, for non-NixOS Linux)";
115→    };
116→
117→    # Important directories and files
118→    directories = mkOption {
119→      type = types.attrsOf types.anything;
120→      default = { };
121→      description = "Integration with home-manager's directories option";
122→    };
123→
124→    files = mkOption {
125→      type = types.attrsOf types.anything;
126→      default = { };
127→      description = "Integration with home-manager's files option";
128→    };
129→
130→    # Service module
131→    serviceConfig = mkOption {
132→      type = types.attrsOf types.anything;
133→      default = { };
134→      description = "Optional systemd service configuration override";
135→    };
136→  };
137→
138→  config = mkIf cfg.enable {
139→    home.packages = [ cfg.tailscaled.package ];
140→
141→    # Declare directories and files for home-manager
142→    home.file.".local/share/tailscale/tailscaled.state" = {
143→      source = config.lib.file.mkOutOfStoreSymlink "${config.home.homeDirectory}/.local/state/tailscale/tailscaled.state";
144→      force = true;
145→    };
146→
147→    # Tailscaled service
148→    systemd.user.services.tailscaled = mkIf configEnabled {
149→      Unit = {
150→        Description = "Tailscale VPN daemon";
151→        After = [ "network-online.target" ];
152→        Wants = [ "network-online.target" ];
153→      };
154→
155→      Service = {
156→        ExecStart = "${pkgs.tailscale}/bin/tailscaled --state=${config.xdg.dataHome}/tailscale/tailscaled.state --socket=${cfg.tailscaled.socketPath}";
157→        Restart = "on-failure";
158→        RestartSec = 5;
159→      }
160→      // cfg.serviceConfig.service or { };
161→
162→      Install.WantedBy = [ "default.target" ];
163→    };
164→
165→    # Tailscale up service (runs once to connect)
166→    systemd.user.services.tailscale-up = mkIf configEnabled {
167→      Unit = {
168→        Description = "Connect Tailscale to network";
169→        After = [ "tailscaled.service" ];
170→        Requires = [ "tailscaled.service" ];
171→      };
172→
173→      Service =
174→        let
175→          authKeyArg =
176→            if cfg.authKey != "" then
177→              "--authkey=${cfg.authKey}"
178→            else if cfg.authKeyFile != "" then
179→              "--authkey-file=${cfg.authKeyFile}"
180→            else
181→              "";
182→
183→          upArgs =
184→            lib.filter (x: x != "") [
185→              authKeyArg
186→              (optionalString cfg.acceptRoutes "--accept-routes")
187→              (optionalString cfg.advertiseExitNode "--advertise-exit-node")
188→              (optionalString (cfg.useExitNode != "") "--exit-node=${cfg.useExitNode}")
189→            ]
190→            ++ cfg.extraUpArgs;
191→
192→          upCommand = "${pkgs.tailscale}/bin/tailscale up ${concatStringsSep " " upArgs}";
193→        in
194→        {
195→          Type = "oneshot";
196→          RemainAfterExit = true;
197→          ExecStart = upCommand;
198→          ExecStop = "${pkgs.tailscale}/bin/tailscale down";
199→        };
200→
201→      Install.WantedBy = [ "default.target" ];
202→    };
203→
204→    home.activation.createTailscaleDirs = config.lib.dag.entryAfter [ "writeBoundary" ] ''
205→      TAILSCALE_STATE_DIR="${config.xdg.dataHome}/tailscale"
206→      TAILSCALE_RUN_DIR="$(dirname "${cfg.tailscaled.socketPath}")"
207→
208→      # Create directories
209→      $DRY_RUN_CMD mkdir -p "$TAILSCALE_STATE_DIR"
210→      $DRY_RUN_CMD mkdir -p "$TAILSCALE_RUN_DIR"
211→
212→      # Set proper permissions
213→      $DRY_RUN_CMD chmod 700 "$TAILSCALE_STATE_DIR"
214→      $DRY_RUN_CMD chmod 700 "$TAILSCALE_RUN_DIR"
215→    '';
216→
217→    # Install system-level tailscaled service (requires sudo)
218→    # Uses nix-generated service file for full declarative config
219→    home.activation.installTailscaleService = mkIf cfg.installSystemService (
220→      config.lib.dag.entryAfter [ "writeBoundary" ] ''
221→                SERVICE_FILE="/etc/systemd/system/tailscaled.service"
222→                NIX_SERVICE="${tailscaledServiceFile}"
223→                SUDOERS_FILE="/etc/sudoers.d/nix-tailscale"
224→
225→                # Resolve an elevated command helper
226→                SUDO_CMD=""
227→                if command -v sudo >/dev/null 2>&1; then
228→                  SUDO_CMD="sudo"
229→                elif [ -x /run/wrappers/bin/sudo ]; then
230→                  # NixOS puts sudo in /run/wrappers/bin
231→                  SUDO_CMD="/run/wrappers/bin/sudo"
232→                elif [ -x /usr/bin/sudo ]; then
233→                  SUDO_CMD="/usr/bin/sudo"
234→                elif command -v doas >/dev/null 2>&1; then
235→                  SUDO_CMD="doas"
236→                elif [ -x /usr/bin/doas ]; then
237→                  SUDO_CMD="/usr/bin/doas"
238→                elif [ "$(id -u)" -ne 0 ]; then
239→                  echo "Tailscale system service installation requires root privileges, but sudo/doas is not available." >&2
240→                  echo "Either install sudo, configure doas, or run home-manager as root." >&2
241→                  exit 1
242→                fi
243→
244→                run_root_cmd() {
245→                  if [ -n "$SUDO_CMD" ]; then
246→                    ''${DRY_RUN_CMD:-} "$SUDO_CMD" "$@"
247→                  else
248→                    ''${DRY_RUN_CMD:-} "$@"
249→                  fi
250→                }
251→
252→                # Only install if service file differs from nix-generated one
253→                if ! cmp -s "$NIX_SERVICE" "$SERVICE_FILE" 2>/dev/null; then
254→                  echo "Installing tailscaled systemd service (requires root)..."
255→                  run_root_cmd cp "$NIX_SERVICE" "$SERVICE_FILE"
256→                  run_root_cmd systemctl daemon-reload
257→                  run_root_cmd systemctl enable tailscaled
258→                  echo "Tailscaled service installed."
259→                fi
260→
