 66→          "amdgpu.abmlevel=3" # auto backlight management
 67→          "amdgpu.runpm=1" # runtime power management for GPU
 68→          "amd_pstate=active" # AMD P-state driver (better than acpi-cpufreq)
 69→          "amdgpu.dcdebugmask=0x410" # disable PSR and REPLAY to fix screen flickering
 70→        ];
 71→
 72→        # Networking
 73→        networking.hostName = "matic";
 74→        networking.networkmanager.enable = true;
 75→        networking.networkmanager.wifi.powersave = true;
 76→
 77→        # Enable fish shell
 78→        programs.fish.enable = true;
 79→
 80→        # User configuration
 81→        users.users.${username} = {
 82→          isNormalUser = true;
 83→          extraGroups = [
 84→            "wheel"
 85→            "networkmanager"
 86→            "input"
 87→            "video"
 88→            "audio"
 89→            "docker"
 90→          ];
 91→          home = "/home/${username}";
 92→          shell = pkgs.fish;
 93→          initialPassword = "changemeow"; # Change this after first login with: passwd
 94→        };
 95→
 96→        # Docker
 97→        virtualisation.docker.enable = true;
 98→
 99→        security.sudo.wheelNeedsPassword = false;
100→
101→        # Immutable root — prevents rm -rf / by blocking top-level entry removal
102→        systemd.services.immutable-root = {
103→          description = "Set immutable flag on /";
104→          wantedBy = [ "multi-user.target" ];
105→          serviceConfig = {
106→            Type = "oneshot";
107→            RemainAfterExit = true;
108→            ExecStart = "${pkgs.e2fsprogs}/bin/chattr +i /";
109→            ExecStop = "${pkgs.e2fsprogs}/bin/chattr -i /";
110→          };
111→        };
112→        # Keyd configuration (Linux desktop only)
113→        services.keyd.enable = true;
114→        users.groups.keyd = { };
115→        systemd.services.keyd.serviceConfig = {
116→          CapabilityBoundingSet = [ "CAP_SETGID" ];
117→          AmbientCapabilities = [ "CAP_SETGID" ];
118→        };
119→        systemd.services.keyd.restartTriggers = [
120→          (builtins.hashFile "sha256" ../../config/keyd/default.conf)
121→        ];
122→        environment.etc."keyd/default.conf".source = ../../config/keyd/default.conf;
123→
124→        # Input remapping (xremap)
125→        hardware.uinput.enable = true;
126→        services.udev.extraRules = ''
127→          KERNEL=="uinput", GROUP="input", TAG+="uaccess", MODE:="0660", OPTIONS+="static_node=uinput"
128→          KERNEL=="event*", ATTRS{name}=="keyd virtual keyboard", GROUP="input", MODE:="0660"
129→          KERNEL=="event*", ATTRS{name}=="keyd virtual pointer", GROUP="input", MODE:="0660"
130→        '';
131→
132→        # AMD graphics with hardware acceleration
133→        hardware.graphics.enable = true;
134→        hardware.graphics.extraPackages = with pkgs; [
135→          libva
136→          libva-vdpau-driver
137→          libvdpau-va-gl
138→        ];
139→
140→        # Thunderbolt support
141→        services.hardware.bolt.enable = true;
142→
143→        # GNOME Keyring - auto-unlocks GPG key on login via PAM
144→        services.gnome.gnome-keyring.enable = true;
145→
146→        # Unlock GNOME Keyring via TPM2 credential at login (PAM exec).
147→        # Runs in the PAM session stack right after pam_gnome_keyring starts the daemon,
148→        # so there are no timing/retry issues. Runs as root (can access TPM), then uses
149→        # runuser to speak the control socket protocol as the target user (SO_PEERCRED).
150→        #
151→        # Credential stored at /etc/credstore.encrypted/gnome-keyring.cred — create once with:
152→        #   sudo bash -c 'mkdir -p /etc/credstore.encrypted && \
153→        #     systemd-ask-password "Keyring password:" | \
154→        #     systemd-creds encrypt --name=gnome-keyring --with-key=tpm2+host \
155→        #     - /etc/credstore.encrypted/gnome-keyring.cred'
156→
157→        # Fingerprint authentication
158→        services.fprintd.enable = true;
159→        security.pam.services.greetd = {
160→          fprintAuth = true;
161→          enableGnomeKeyring = true;
162→          rules.session = {
163→            # Run after pam_gnome_keyring (which starts the daemon but can't unlock
164→            # on fingerprint login). Decrypts the TPM2 credential and sends the
165→            # password to the running daemon via the control socket protocol.
166→            gnome_keyring_tpm_unlock =
167→              let
168→                # Speaks the gnome-keyring control socket protocol directly.
169→                # gnome-keyring-daemon --unlock (v48) ignores GNOME_KEYRING_CONTROL
170→                # and always starts a new instance, so we bypass it entirely.
171→                #
172→                # Protocol (all big-endian):
173→                #   1. connect to $XDG_RUNTIME_DIR/keyring/control (UNIX stream)
174→                #   2. send \x00 — daemon reads our UID via SO_PEERCRED
175→                #   3. send [oplen:4][op=1:4][pwlen:4][password bytes]
176→                #          where oplen = 8 + 4 + len(password)
177→                #   4. read [8:4][result:4] — result 0 = OK
178→                unlockPy = pkgs.writeScript "unlock-gnome-keyring.py" (
179→                  builtins.readFile (
180→                    pkgs.replaceVars ./unlock-gnome-keyring.py {
181→                      inherit (pkgs) python3;
182→                    }
183→                  )
184→                );
185→
186→                # PAM exec script: runs as root, decrypts TPM credential, then
187→                # uses runuser to run the Python unlock as the target user.
188→                pamScript = pkgs.writeShellScript "pam-gnome-keyring-tpm-unlock" (
189→                  builtins.readFile (
190→                    pkgs.replaceVars ./pam-gnome-keyring-tpm-unlock.sh {
191→                      logger = "${pkgs.util-linux}/bin/logger";
192→                      systemd_creds = "${pkgs.systemd}/bin/systemd-creds";
193→                      id = "${pkgs.coreutils}/bin/id";
194→                      sleep = "${pkgs.coreutils}/bin/sleep";
195→                      env = "${pkgs.coreutils}/bin/env";
196→                      runuser = "${pkgs.util-linux}/bin/runuser";
197→                      unlock_py = unlockPy;
198→                    }
199→                  )
200→                );
201→              in
202→              {
203→                order = config.security.pam.services.greetd.rules.session.gnome_keyring.order + 10;
204→                control = "optional";
205→                modulePath = "${pkgs.pam}/lib/security/pam_exec.so";
206→                args = [
207→                  "type=open_session"
208→                  "${pamScript}"
209→                ];
210→              };
211→          };
212→        };
213→        security.pam.services.hyprlock = {
214→          fprintAuth = true;
215→        };
216→        security.pam.services.sudo = {
217→          fprintAuth = true;
218→        };
219→
220→        # Firmware updates
221→        services.fwupd.enable = true;
222→
223→        # Power management
224→        powerManagement.enable = true;
225→        powerManagement.powertop.enable = true;
226→        services.upower.enable = true;
227→        services.power-profiles-daemon.enable = false;
228→        services.auto-cpufreq = {
229→          enable = true;
230→          settings = {
231→            battery = {
232→              governor = "powersave";
233→              turbo = "never";
234→            };
235→            charger = {
236→              governor = "performance";
237→              turbo = "auto";
238→            };
239→          };
240→        };
241→
242→        # Power button behavior - lock screen instead of shutdown
243→        services.logind.settings.Login.HandlePowerKey = "lock";
244→        # On battery: suspend immediately when lid closed
245→        # On AC: ignore lid close — let hypridle's 30-min idle timer handle suspension
246→        services.logind.settings.Login.HandleLidSwitch = "suspend";
247→        services.logind.settings.Login.HandleLidSwitchExternalPower = "ignore";
248→
249→        # Auto timezone (via geolocation)
250→        services.geoclue2.enable = true;
251→        services.localtimed.enable = true;
252→
253→        # Audio (PipeWire)
254→        services.pipewire = {
255→          enable = true;
256→          alsa.enable = true;
257→          alsa.support32Bit = true;
258→          pulse.enable = true;
259→          wireplumber.enable = true;
260→        };
261→        services.pulseaudio.enable = false;
262→        security.rtkit.enable = true;
263→
264→        # Bluetooth
265→        hardware.bluetooth.enable = true;
266→        hardware.bluetooth.powerOnBoot = true;
267→
268→        # Login manager (greetd + tuigreet)
269→        services.greetd = {
270→          enable = true;
271→          settings = {
272→            default_session = {
273→              command = "${pkgs.tuigreet}/bin/tuigreet --time --remember --remember-session --asterisks --sessions /etc/greetd/wayland-sessions";
274→              user = "greeter";
275→            };
276→          };
277→        };
278→        # Ensure fprintd is ready before greetd starts to avoid PAM fingerprint timeout
279→        systemd.services.greetd.after = [ "fprintd.service" ];
280→        systemd.services.greetd.wants = [ "fprintd.service" ];
281→
282→        # Disk management
283→        services.gvfs.enable = true; # For automounting external drives in Nautilus and managing disk permissions
284→        services.udisks2.enable = true; # For better integration with external drives, including NTFS support and proper permissions handling
285→
286→        # Provide Hyprland session file for tuigreet to discover
287→        environment.etc."greetd/wayland-sessions/hyprland.desktop".text = ''
288→          [Desktop Entry]
289→          Name=Hyprland
290→          Exec=uwsm start hyprland-uwsm.desktop
291→          Type=Application
292→        '';
293→
294→        programs.hyprland = {
295→          enable = true;
296→          package = pkgs.hyprland;
297→          portalPackage = pkgs.xdg-desktop-portal-hyprland;
298→          xwayland.enable = true;
299→          withUWSM = true;
300→        };
301→
302→        # Steam (for Wallpaper Engine assets)
303→        programs.steam.enable = true;
304→
305→        programs.dconf.enable = true;
306→
307→        xdg.portal = {
308→          enable = true;
309→          extraPortals = with pkgs; [
310→            xdg-desktop-portal-gtk
311→          ];
312→          config = {
313→            hyprland = {
314→              default = [
315→                "hyprland"
316→                "gtk"
317→              ];
318→              "org.freedesktop.impl.portal.Settings" = [
319→                "darkman"
320→                "gtk"
321→              ];
322→            };
323→          };
324→        };
325→
326→        # WiFi MT7925e fix (disable ASPM)
327→        boot.extraModprobeConfig = ''
328→          options mt7925e disable_aspm=1
329→        '';
330→
331→        # Enable nix-ld for running dynamically linked binaries (CrowdStrike, Kolide, etc.)
332→        programs.nix-ld.enable = true;
333→        programs.nix-ld.libraries = with pkgs; [
334→          # Common libraries needed by security tools
335→          curl
336→          glibc
337→          libgcc
338→          libnl
339→          openssl
340→          zlib
341→        ];
342→
343→        # NixOS-level nix settings (complements home-manager nix/)
344→        nix = {
345→          channel.enable = false;
346→          settings = {
347→            nix-path = lib.mkForce "nixpkgs=/etc/nix/inputs/nixpkgs";
348→            trusted-users = [
349→              username
350→              "@wheel"
351→              "root"
352→            ];
353→          };
354→        };
355→        environment.etc."nix/inputs/nixpkgs".source = "${inputs.nixpkgs}";
356→
357→        system.stateVersion = "24.11";
358→      }
359→    )
360→
361→    # Fonts
362→    {
363→      nixpkgs.pkgs = pkgs;
364→
365→      fonts.fontconfig.enable = true;
366→      fonts.packages = with pkgs; [
367→        inter
368→        ipaexfont
369→        ipafont
370→        joypixels
371→        nerd-fonts.jetbrains-mono
372→        noto-fonts-cjk-sans
